import React from 'react';
import { Select, Cell } from '@salutejs/plasma-web';
export function App() {
    const items = [
        { label: 'Алексей Смирнов' },
        { label: 'Екатерина Иванова' },
    ];
    const renderItem = ({ label }) => (
        <Cell
            view="default"
            title={label}
            label="Top left"
            contentRight={<Cell view="default" title="Bottom right" label="Top right" />}
        />
    )
    return (
        <div style={{ display: 'block', height: "350px" }}>
            <Autocomplete suggestions={items} threshold={0} label="Label" placeholder="Placeholder" renderItem={renderItem} />
        </div>
    );
}
